import SwiftUI

// MARK: - Badge helper (internal for unit test access via @testable import)
func badgeLabel(for count: Int) -> String? {
    guard count > 0 else { return nil }
    return count >= 100 ? "99+" : "\(count)"
}

struct HomeHeaderView: View {
    let userProfile: any UserProfileProviding
    let notificationCenter: any NotificationCenterProviding
    var onBellTap: () -> Void = {}
    var onAvatarTap: () -> Void = {}

    var body: some View {
        HStack(spacing: 12) {
            Text("운테크")
                .font(.system(size: 20, weight: .bold))
                .foregroundStyle(DesignTokens.ink)
                .lineLimit(1)
                .minimumScaleFactor(0.7)
                .accessibilityIdentifier("HomeWordmark")

            Spacer(minLength: 8)

            // Bell button with unread badge overlay
            Button(action: onBellTap) {
                ZStack(alignment: .topTrailing) {
                    Image(systemName: "bell")
                        .font(.system(size: 22))
                        .foregroundStyle(DesignTokens.ink)
                        .frame(width: 44, height: 44)

                    if let label = badgeLabel(for: notificationCenter.unreadCount) {
                        Text(label)
                            .font(.system(size: 10, weight: .bold))
                            .foregroundStyle(.white)
                            .lineLimit(1)
                            .minimumScaleFactor(0.7)
                            .padding(.horizontal, 4)
                            .padding(.vertical, 2)
                            .background(Color.red)
                            .clipShape(Capsule())
                            .offset(x: 6, y: -4)
                            .accessibilityIdentifier("HomeBellBadge")
                    }
                }
            }
            .buttonStyle(.plain)
            .accessibilityLabel("알림 \(notificationCenter.unreadCount)개")
            .accessibilityIdentifier("HomeBellButton")

            // Avatar circle button
            Button(action: onAvatarTap) {
                Circle()
                    .fill(DesignTokens.avatarBg)
                    .frame(width: 36, height: 36)
                    .overlay {
                        Text(userProfile.avatarInitial)
                            .font(.system(size: 15, weight: .semibold))
                            .foregroundStyle(DesignTokens.ink)
                            .lineLimit(1)
                            .minimumScaleFactor(0.7)
                    }
            }
            .buttonStyle(.plain)
            .accessibilityLabel("프로필 \(userProfile.displayName)")
            .accessibilityIdentifier("HomeAvatarButton")
        }
        .padding(.horizontal, 16)
        .padding(.vertical, 12)
        .background(DesignTokens.bg)
    }
}

import SwiftUI

struct HomeDashboardView: View {
    @EnvironmentObject var homeDeps: HomeDependencies
    @State private var navigationPath: [HomeRoute] = []
    @State private var bellTapCount = 0
    @State private var avatarTapCount = 0

    var body: some View {
        VStack(spacing: 0) {
            HomeHeaderView(
                userProfile: homeDeps.userProfile,
                notificationCenter: homeDeps.notificationCenter,
                onBellTap: { bellTapCount += 1 },
                onAvatarTap: { avatarTapCount += 1 }
            )

            Rectangle()
                .fill(DesignTokens.headerBorder)
                .frame(height: 1)

            NavigationStack(path: $navigationPath) {
                ScrollView {
                    Text("준비중")
                        .accessibilityIdentifier("HomeDashboardContentPlaceholder")
                }
                .toolbar(.hidden, for: .navigationBar)
                .navigationDestination(for: HomeRoute.self) { route in
                    switch route {
                    case .investing:
                        InvestingPlaceholderView()
                    case .event:
                        EventPlaceholderView()
                    case .today:
                        TodayPlaceholderView()
                    case .tabooPlaceholder:
                        TabooPlaceholderView()
                    case .practicePlaceholder:
                        PracticePlaceholderView()
                    }
                }
            }

            HomeTabBarPlaceholderView()
                .accessibilityIdentifier("HomeTabBarPlaceholder")
        }
        .accessibilityIdentifier("HomeDashboardRoot")
        // Spy counters: opacity 0 so invisible, but readable by XCUITest via accessibilityIdentifier
        .overlay(alignment: .topLeading) {
            VStack(spacing: 0) {
                Text("\(bellTapCount)")
                    .accessibilityIdentifier("HomeBellTapCount")
                Text("\(avatarTapCount)")
                    .accessibilityIdentifier("HomeAvatarTapCount")
            }
            .opacity(0)
            .allowsHitTesting(false)
        }
        // Hidden push trigger buttons for UI tests (AC-10)
        .overlay(alignment: .bottomLeading) {
            VStack(spacing: 0) {
                Button {
                    navigationPath.append(.investing)
                } label: {
                    Rectangle().fill(Color.clear).frame(width: 1, height: 1)
                }
                .accessibilityIdentifier("HomeNavPushInvesting")
                .opacity(0)

                Button {
                    navigationPath.append(.event(WeeklyEvent()))
                } label: {
                    Rectangle().fill(Color.clear).frame(width: 1, height: 1)
                }
                .accessibilityIdentifier("HomeNavPushEvent")
                .opacity(0)

                Button {
                    navigationPath.append(.today)
                } label: {
                    Rectangle().fill(Color.clear).frame(width: 1, height: 1)
                }
                .accessibilityIdentifier("HomeNavPushToday")
                .opacity(0)

                Button {
                    navigationPath.append(.tabooPlaceholder)
                } label: {
                    Rectangle().fill(Color.clear).frame(width: 1, height: 1)
                }
                .accessibilityIdentifier("HomeNavPushTaboo")
                .opacity(0)

                Button {
                    navigationPath.append(.practicePlaceholder)
                } label: {
                    Rectangle().fill(Color.clear).frame(width: 1, height: 1)
                }
                .accessibilityIdentifier("HomeNavPushPractice")
                .opacity(0)
            }
        }
    }
}

